// ============================================
// WF-OUTBOUND: PARSE & VALIDATE - V3
// Corrigido para detectar mimeType incompleto
// ============================================

const webhookData = $input.first().json;
const webhook = webhookData.body || webhookData;

if (webhook.event && webhook.event !== 'message_created') {
  return [{ json: { skip: true, reason: `Evento ignorado: ${webhook.event}` } }];
}

// ============================================
// FILTROS
// ============================================

if (webhook.private === true) {
  return [{ json: { skip: true, reason: 'Nota privada' } }];
}

if (webhook.message_type !== 'outgoing') {
  return [{ json: { skip: true, reason: `Tipo ignorado: ${webhook.message_type}` } }];
}

if (webhook.sender?.type === 'agent_bot') {
  return [{ json: { skip: true, reason: 'Bot' } }];
}

if (!webhook.conversation) {
  return [{ json: { skip: true, reason: 'Sem conversation' } }];
}

// ============================================
// EXTRAIR DADOS
// ============================================

const conversation = webhook.conversation || {};
const contact = conversation.meta?.sender || {};
const contactInbox = conversation.contact_inbox || {};
const inbox = webhook.inbox || {};

// ============================================
// FUNÇÕES AUXILIARES
// ============================================

function isValidPhone(phone) {
  if (!phone) return false;
  const cleaned = phone.replace(/\D/g, '');
  return cleaned.length >= 10 && cleaned.length <= 15;
}

function isUUID(str) {
  if (!str) return false;
  const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
  return uuidRegex.test(str);
}

function cleanPhone(phone) {
  if (!phone) return '';
  let cleaned = phone.replace(/\D/g, '');
  cleaned = cleaned.replace(/^\+/, '');
  return cleaned;
}

// ============================================
// FUNÇÃO PARA DETECTAR TIPO DE MÍDIA
// ============================================

function detectMediaType(mimeType, fileName) {
  if (!mimeType) return 'document';

  const mime = mimeType.toLowerCase();

  // Verificar se começa com tipo (com ou sem barra)
  // Exemplos: "audio/mpeg", "audio", "image/jpeg", "image"

  if (mime.startsWith('image/') || mime === 'image') {
    return 'image';
  }

  if (mime.startsWith('audio/') || mime === 'audio') {
    return 'audio';
  }

  if (mime.startsWith('video/') || mime === 'video') {
    return 'video';
  }

  // Verificar por extensão do arquivo se mimeType não ajudar
  if (fileName) {
    const ext = fileName.split('.').pop()?.toLowerCase();

    const imageExts = ['jpg', 'jpeg', 'png', 'gif', 'webp'];
    const audioExts = ['mp3', 'ogg', 'wav', 'aac', 'opus', 'm4a'];
    const videoExts = ['mp4', 'avi', 'mov', 'mkv', 'webm', '3gp'];

    if (imageExts.includes(ext)) return 'image';
    if (audioExts.includes(ext)) return 'audio';
    if (videoExts.includes(ext)) return 'video';
  }

  // Fallback para document
  return 'document';
}

// ============================================
// EXTRAIR TELEFONE DO DESTINATÁRIO
// ============================================

let sourceId = contactInbox.source_id || '';
let recipientPhone = '';
let isGroup = false;

if (sourceId.includes('@g.us')) {
  isGroup = true;
  recipientPhone = sourceId;
} else {
  if (!isUUID(sourceId) && isValidPhone(sourceId)) {
    recipientPhone = cleanPhone(sourceId);
  }

  if (!recipientPhone) {
    const phoneNumber = contact.phone_number || '';
    if (isValidPhone(phoneNumber)) {
      recipientPhone = cleanPhone(phoneNumber);
    }
  }

  if (!recipientPhone) {
    const identifier = contact.identifier || '';
    if (!isUUID(identifier) && isValidPhone(identifier)) {
      recipientPhone = cleanPhone(identifier);
    }
  }

  if (!recipientPhone && contact.custom_attributes?.phone) {
    const customPhone = contact.custom_attributes.phone;
    if (isValidPhone(customPhone)) {
      recipientPhone = cleanPhone(customPhone);
    }
  }
}

if (!recipientPhone) {
  return [{
    json: {
      skip: true,
      reason: 'Não foi possível extrair telefone do destinatário',
      debug: {
        sourceId: sourceId,
        contactIdentifier: contact.identifier,
        contactPhone: contact.phone_number,
        isUUID: isUUID(sourceId)
      }
    }
  }];
}

// ============================================
// EXTRAIR ANEXOS/MÍDIA
// ============================================

const attachments = webhook.attachments || [];
const hasMedia = attachments.length > 0;

let messageType = 'text';
let mediaUrl = null;
let fileName = null;
let mimeType = null;
let caption = '';

if (hasMedia) {
  const att = attachments[0];
  mediaUrl = att.data_url;
  fileName = att.file_name || 'arquivo';
  mimeType = att.file_type || 'application/octet-stream';

  // Usar função melhorada de detecção
  messageType = detectMediaType(mimeType, fileName);

  caption = webhook.content || '';
}

// ============================================
// RETORNAR DADOS NORMALIZADOS
// ============================================

return [{
  json: {
    skip: false,

    // IDs Chatwoot
    chatwootMessageId: webhook.id,
    chatwootConversationId: conversation.id,
    chatwootInboxId: inbox.id,
    chatwootContactId: contact.id,

    // Remetente (agente)
    senderName: webhook.sender?.available_name || webhook.sender?.name || 'Atendente',
    senderId: webhook.sender?.id,

    // Destinatário
    recipientPhone: recipientPhone,
    sourceId: sourceId,
    isGroup: isGroup,
    contactName: contact.name || recipientPhone,

    // Mensagem
    messageContent: webhook.content || '',
    messageType: messageType,

    // Mídia
    hasMedia: hasMedia,
    mediaUrl: mediaUrl,
    fileName: fileName,
    mimeType: mimeType,
    caption: caption,

    // Metadata
    timestamp: new Date().toISOString()
  }
}];

// ============================================
// WF-OUTBOUND: MAP INBOX TO PLATFORM - V2
// Incluindo inboxes de GRUPOS
// ============================================

const data = $input.first().json;

const INBOX_CONFIG = {
  // ============================================
  // RECEPÇÃO - Individual e Grupos
  // ============================================
  4: {
    platform: 'uazapi',
    inboxName: 'Recepção',
    whatsappNumber: '556183008973',
    baseUrl: 'https://schappo.uazapi.com',
    token: '88950a6f-0824-4c1d-a4b6-023f4c66cb28'
  },
  10: {
    platform: 'uazapi',
    inboxName: 'Recepção Grupos',
    whatsappNumber: '556183008973',  // Mesma instância da Recepção
    baseUrl: 'https://schappo.uazapi.com',
    token: '88950a6f-0824-4c1d-a4b6-023f4c66cb28'
  },

  // ============================================
  // EEG - Individual e Grupos
  // ============================================
  5: {
    platform: 'uazapi',
    inboxName: 'EEG',
    whatsappNumber: '556192894339',
    baseUrl: 'https://schappo.uazapi.com',
    token: '6220a163-28da-40dc-ae09-cc2bdbe695f6'
  },
  11: {
    platform: 'uazapi',
    inboxName: 'EEG Grupos',
    whatsappNumber: '556192894339',  // Mesma instância do EEG
    baseUrl: 'https://schappo.uazapi.com',
    token: '6220a163-28da-40dc-ae09-cc2bdbe695f6'
  },

  // ============================================
  // GERAL - 360Dialog
  // ============================================
  8: {
    platform: '360dialog',
    inboxName: 'Geral',
    whatsappNumber: '556133455701',
    baseUrl: 'https://waba-v2.360dialog.io',
    token: 'U7BrceqxGJ4IQpsMRcOwJZbDAK'
  }
};

// ============================================
// BUSCAR CONFIGURAÇÃO DO INBOX
// ============================================

const config = INBOX_CONFIG[data.chatwootInboxId];

if (!config) {
  return [{ 
    json: { 
      ...data, 
      skip: true, 
      reason: `Inbox ${data.chatwootInboxId} não configurado` 
    } 
  }];
}

// ============================================
// PREPARAR TELEFONE PARA ENVIO
// ============================================

let phoneForSend = data.recipientPhone.replace(/^\+/, '');

// Se for grupo e não tiver @g.us, adicionar
if (data.isGroup && !phoneForSend.includes('@g.us')) {
  phoneForSend = phoneForSend + '@g.us';
}

// ============================================
// RETORNAR DADOS COM CONFIGURAÇÃO
// ============================================

return [{
  json: {
    ...data,
    phoneForSend,
    platform: config.platform,
    inboxName: config.inboxName,
    whatsappNumber: config.whatsappNumber,
    baseUrl: config.baseUrl,
    token: config.token
  }
}];

const prevData = $('Code - Map Inbox to Platform').first().json;
const binary = $input.first().binary;
return [{ json: prevData, binary: binary }];

// ============================================
// WF-OUTBOUND: PREPARAR 360 MEDIA - V3
// Com nome do remetente no caption
// ============================================

const data = $input.first().json;

// Função para detectar tipo de mídia
function detectMediaType(mimeType, fileName) {
  if (!mimeType) return 'document';

  const mime = mimeType.toLowerCase();

  // Verificar se começa com tipo (com ou sem barra)
  if (mime.startsWith('image/') || mime === 'image') {
    return 'image';
  }

  if (mime.startsWith('audio/') || mime === 'audio') {
    return 'audio';
  }

  if (mime.startsWith('video/') || mime === 'video') {
    return 'video';
  }

  // Verificar por extensão do arquivo
  if (fileName) {
    const ext = fileName.split('.').pop()?.toLowerCase();

    const imageExts = ['jpg', 'jpeg', 'png', 'gif', 'webp'];
    const audioExts = ['mp3', 'ogg', 'wav', 'aac', 'opus', 'm4a'];
    const videoExts = ['mp4', 'avi', 'mov', 'mkv', 'webm', '3gp'];

    if (imageExts.includes(ext)) return 'image';
    if (audioExts.includes(ext)) return 'audio';
    if (videoExts.includes(ext)) return 'video';
  }

  return 'document';
}

// Detectar tipo de mídia corretamente
const mediaType = detectMediaType(data.mimeType, data.fileName);

// Construir payload conforme documentação 360Dialog
const payload = {
  messaging_product: 'whatsapp',
  recipient_type: 'individual',
  to: data.phoneForSend,
  type: mediaType
};

// Adicionar objeto de mídia com base no tipo
payload[mediaType] = {
  link: data.mediaUrl
};

// Adicionar caption se não for áudio
// Áudio não suporta caption no WhatsApp API
if (mediaType !== 'audio') {
  const captionText = data.caption || data.messageContent || '';

  // Montar caption com nome do remetente
  let finalCaption = '';

  if (data.senderName) {
    if (captionText) {
      finalCaption = '*' + data.senderName + '*:\n' + captionText;
    } else {
      finalCaption = '*' + data.senderName + '*';
    }
  } else {
    finalCaption = captionText;
  }

  // Só adicionar caption se tiver conteúdo
  if (finalCaption) {
    payload[mediaType].caption = finalCaption;
  }
}

// Adicionar filename se for documento
if (mediaType === 'document' && data.fileName) {
  payload[mediaType].filename = data.fileName;
}

return [{
  json: {
    ...data,
    mediaType: mediaType,
    payload360: payload
  }
}];

// ============================================
// PREPARAR PAYLOAD 360DIALOG TEXT
// ============================================

const input = $input.first().json;

// Montar corpo da mensagem com nome do agente
let bodyText = input.messageContent || '';

// Adicionar nome do remetente se existir
if (input.senderName) {
  bodyText = '*' + input.senderName + '*:\n' + bodyText;
}

// Montar payload conforme documentação oficial
const payload = {
  messaging_product: "whatsapp",
  recipient_type: "individual",
  to: input.phoneForSend,
  type: "text",
  text: {
    body: bodyText
  }
};

return [{
  json: {
    ...input,
    payload360: payload
  }
}];

// ============================================
// WF-OUTBOUND: PREPARAR UAZAPI MEDIA
// Prepara payload para envio de mídia via UAZAPI
// ============================================

const data = $input.first().json;

// ============================================
// FUNÇÃO: Detectar tipo de mídia
// ============================================
function detectMediaType(mimeType, fileName) {
  // Se mimeType existir, verificar
  if (mimeType) {
    const mime = mimeType.toLowerCase();

    if (mime.startsWith('image/') || mime === 'image') return 'image';
    if (mime.startsWith('video/') || mime === 'video') return 'video';
    if (mime.startsWith('audio/') || mime === 'audio') return 'audio';
  }

  // Verificar por extensão do arquivo
  if (fileName) {
    const ext = fileName.split('.').pop()?.toLowerCase();

    const imageExts = ['jpg', 'jpeg', 'png', 'gif', 'webp'];
    const audioExts = ['mp3', 'ogg', 'wav', 'aac', 'opus', 'm4a'];
    const videoExts = ['mp4', 'avi', 'mov', 'mkv', 'webm', '3gp'];

    if (imageExts.includes(ext)) return 'image';
    if (audioExts.includes(ext)) return 'audio';
    if (videoExts.includes(ext)) return 'video';
  }

  // Fallback
  return 'document';
}

// ============================================
// PREPARAR DADOS
// ============================================

const mediaType = detectMediaType(data.mimeType, data.fileName);

// Montar texto com nome do remetente
let messageText = '';
const caption = data.caption || data.messageContent || '';

if (data.senderName) {
  if (caption) {
    messageText = '*' + data.senderName + '*:\n' + caption;
  } else {
    messageText = '*' + data.senderName + '*';
  }
} else {
  messageText = caption;
}

// Montar payload para UAZAPI
const uazapiPayload = {
  number: data.phoneForSend || data.recipientPhone,
  type: mediaType,
  file: data.mediaUrl,
  text: messageText,
  filename: data.fileName || 'arquivo'
};

// ============================================
// RETORNAR DADOS
// ============================================

return [{
  json: {
    ...data,
    mediaType: mediaType,
    uazapiPayload: uazapiPayload
  }
}];

// ============================================
// WF-OUTBOUND: PROCESSAR RESPOSTA DE ENVIO
// Extrair messageId do WhatsApp e preparar
// atualização do Chatwoot
// ============================================

const response = $input.first().json;

// Buscar dados originais que foram perdidos na resposta HTTP
const originalData = $('Code - Map Inbox to Platform').first().json;

const chatwootMessageId = originalData.chatwootMessageId || null;
const chatwootConversationId = originalData.chatwootConversationId || null;

// Se não tem IDs do Chatwoot, não tem o que atualizar
if (!chatwootMessageId || !chatwootConversationId) {
  return [{ json: { skip: true, reason: 'Sem IDs do Chatwoot' } }];
}

// ============================================
// EXTRAIR MESSAGE ID DA RESPOSTA
// ============================================
let whatsappMessageId = null;

// 360Dialog retorna: { messages: [{ id: "wamid.xxx" }] }
if (response.messages && Array.isArray(response.messages) && response.messages[0]?.id) {
  whatsappMessageId = input.messages[0].id;
}

// UAZAPI retorna: { messageid: "3EB0xxx", id: "owner:3EB0xxx" }
if (!whatsappMessageId && response.messageid) {
  whatsappMessageId = response.messageid;
}
if (!whatsappMessageId && response.id) {
  whatsappMessageId = response.id;
}

// Fallback: procurar em qualquer campo que pareça um ID
if (!whatsappMessageId) {
  const str = JSON.stringify(response);
  const wamidMatch = str.match(/wamid\.[A-Za-z0-9+/=]+/);
  if (wamidMatch) {
    whatsappMessageId = wamidMatch[0];
  }
}

if (!whatsappMessageId) {
  console.log('⚠️ Não foi possível extrair messageId do WhatsApp');
  return [{ json: { skip: true, reason: 'Sem messageId do WhatsApp', responseData: response } }];
}

console.log('✅ WhatsApp messageId:', whatsappMessageId);
console.log('✅ Chatwoot message:', chatwootConversationId, '/', chatwootMessageId);

return [{
  json: {
    skip: false,
    chatwootMessageId: chatwootMessageId,
    chatwootConversationId: chatwootConversationId,
    whatsappMessageId: whatsappMessageId
  }
}];

